  1→import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
  2→import { addReplyOpinion, getOpinionReply } from "../../../API/Api";
  3→import { useState, useRef } from "react";
  4→import { useAuth } from "../../Context/useAuth";
  5→import { motion, AnimatePresence } from "framer-motion";
  6→import formatPostDate from "../../../helpers/formatDateString";
  7→import VerifiedBadge from "../Badge/VerifiedBadge";
  8→import MentionText from "../mentions/MentionText";
  9→import useTextareaMention from "../mentions/useTextareaMention";
 10→import MentionDropdown from "../mentions/MentionDropdown";
 11→import { getBadgeRingClass } from "../../utils/badgeRingClass";
 12→
 13→const MAX_VISUAL_DEPTH = 3;
 14→
 15→const OpinionsReplyCard = ({ opinionId, depth = 0 }) => {
 16→    const queryClient = useQueryClient();
 17→    const { user, session } = useAuth();
 18→
 19→    const [openReplies, setOpenReplies] = useState(new Set());
 20→    const [replyOpinion, setReplyOpinion] = useState('');
 21→    const [isTypingId, setIsTypingId] = useState('');
 22→    const [showReplyButtonId, setShowReplyButtonId] = useState('');
 23→
 24→    const textAreaRef = useRef(null);
 25→
 26→    const { textareaProps: mentionTextareaProps, dropdownProps: mentionDropdownProps } = useTextareaMention(replyOpinion, setReplyOpinion, textAreaRef, 280, user?.userData?.[0]?.id);
 27→
 28→    const { data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage } = useInfiniteQuery({
 29→        queryKey: ['getReplyOpinion', opinionId],
 30→        queryFn: ({ queryKey, pageParam = null }) => getOpinionReply(queryKey[1], 10, pageParam),
 31→        getNextPageParam: (lastPage) => {
 32→            if (lastPage?.hasMore) {
 33→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 34→                return lastReply.id;
 35→            }
 36→            return undefined;
 37→        },
 38→        enabled: !!opinionId,
 39→    });
 40→
 41→    const handleSubmitReplyOpinion = async (reply, receiver_id, sender_id, parent_id) => {
 42→        try {
 43→            const formadata = new FormData();
 44→            formadata.append('opinion', reply);
 45→            await addReplyOpinion(formadata, receiver_id, sender_id, parent_id, session?.access_token);
 46→            setShowReplyButtonId('');
 47→            setIsTypingId('');
 48→        } catch (error) {
 49→            console.error(error);
 50→        } finally {
 51→            setReplyOpinion('');
 52→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 53→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 54→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion'] });
 55→        }
 56→    };
 57→
 58→    const cancelTyping = () => {
 59→        setIsTypingId('');
 60→        setReplyOpinion('');
 61→        if (textAreaRef.current) {
 62→            textAreaRef.current.blur();
 63→        }
 64→        setShowReplyButtonId('');
 65→    };
 66→
 67→    const visualDepth = Math.min(depth, MAX_VISUAL_DEPTH);
 68→    const opinioData = data?.pages.flatMap((page) => page.data) || [];
 69→
 70→    return (
 71→        <div
 72→            className="rc-thread"
 73→            style={{ '--depth': visualDepth }}
 74→        >
 75→            {opinioData?.map((opinion, index) => {
 76→                const isLast = index === opinioData.length - 1;
 77→                const hideConnector = isLast && !hasNextPage && opinion.reply_count === 0;
 78→
 79→                return (
 80→                    <motion.div
 81→                        className="rc-reply"
 82→                        key={opinion.id}
 83→                        initial={{ opacity: 0, y: 6 }}
 84→                        animate={{ opacity: 1, y: 0 }}
 85→                        transition={{ duration: 0.25, delay: index * 0.03, ease: "easeOut" }}
 86→                    >
 87→                        <div className="rc-avatar-col">
 88→                            <div className={`so-avatar-outer so-avatar-outer--sm ${getBadgeRingClass(opinion.users?.badge)}`}>
 89→                                <img
 90→                                    className="so-avatar so-avatar--sm"
 91→                                    src={opinion.users?.image_url || '../assets/profile.jpg'}
 92→                                    alt={`${opinion?.users?.name || "User"} profile picture`}
 93→                                />
 94→                            </div>
 95→                            <div className={`rc-connector ${hideConnector ? 'rc-connector--hidden' : ''}`} />
 96→                        </div>
 97→
 98→                        <div className="rc-content">
 99→                            <div className="so-header-row">
100→                                <span className="so-username" style={{ fontSize: '0.8rem' }}>{opinion.users?.name}</span>
101→                                <VerifiedBadge badge={opinion.users?.badge} size={12}/>
102→                                <span className="so-dot">·</span>
103→                                <span className="so-date" style={{ fontSize: '0.7rem' }}>{formatPostDate(opinion.created_at)}</span>
104→                            </div>
105→
106→                            <div className="rc-body">
107→                                <MentionText text={opinion.opinion} />
108→                            </div>
109→
110→                            <div className="rc-actions">
111→                                {opinion.reply_count > 0 && (
112→                                    <button
113→                                        className="rc-show-replies"
114→                                        onClick={() => setOpenReplies(prev => {
115→                                            const next = new Set(prev);
116→                                            next.has(opinion.id) ? next.delete(opinion.id) : next.add(opinion.id);
117→                                            return next;
118→                                        })}
119→                                    >
120→                                        {openReplies.has(opinion.id) ? 'Hide' : 'Show'} {opinion.reply_count} {opinion.reply_count === 1 ? 'reply' : 'replies'}
121→                                    </button>
122→                                )}
123→                                <button
124→                                    className="rc-reply-btn"
125→                                    onClick={() => setShowReplyButtonId(
126→                                        showReplyButtonId === opinion.id ? '' : opinion.id
127→                                    )}
128→                                >
129→                                    Reply
130→                                </button>
131→                            </div>
132→
133→                            <AnimatePresence>
134→                                {showReplyButtonId === opinion.id && (
135→                                    <motion.div
136→                                        initial={{ height: 0, opacity: 0 }}
137→                                        animate={{ height: "auto", opacity: 1 }}
138→                                        exit={{ height: 0, opacity: 0 }}
139→                                        transition={{ duration: 0.2 }}
140→                                        className="rc-inline-composer"
141→                                    >
142→                                        <textarea
143→                                            ref={textAreaRef}
144→                                            maxLength={280}
145→                                            value={replyOpinion}
146→                                            onChange={(e) => { setReplyOpinion(e.target.value); mentionTextareaProps.onChange(e); }}
147→                                            onKeyDown={mentionTextareaProps.onKeyDown}
148→                                            onKeyUp={mentionTextareaProps.onKeyUp}
149→                                            onFocus={() => setIsTypingId(opinion.id)}
150→                                            className="ov-reply-input"
151→                                            placeholder={`Reply to ${opinion.users?.name}...`}
152→                                            rows={1}
153→                                        />
154→                                        <MentionDropdown {...mentionDropdownProps} />
155→
156→                                        {isTypingId === opinion.id && (
157→                                            <div className="ov-composer-actions">
158→                                                <span className="ov-char-count">
159→                                                    {replyOpinion.length > 0 ? `${replyOpinion.length}/280` : ''}
160→                                                </span>
161→                                                <div className="ov-btn-row">
162→                                                    <button onClick={cancelTyping} className="ov-btn-cancel">Cancel</button>
163→                                                    <button
164→                                                        disabled={replyOpinion.trim().length === 0}
165→                                                        onClick={() => handleSubmitReplyOpinion(replyOpinion, opinion.users.id, user?.userData[0].id, opinion.id)}
166→                                                        className={`ov-btn-submit ${replyOpinion.trim().length === 0 ? 'ov-btn-disabled' : ''}`}
167→                                                    >
168→                                                        Reply
169→                                                    </button>
170→                                                </div>
171→                                            </div>
172→                                        )}
173→                                    </motion.div>
174→                                )}
175→                            </AnimatePresence>
176→
177→                            <AnimatePresence>
178→                                {openReplies.has(opinion.id) && (
179→                                    <motion.div
180→                                        initial={{ opacity: 0 }}
181→                                        animate={{ opacity: 1 }}
182→                                        exit={{ opacity: 0 }}
183→                                        transition={{ duration: 0.2 }}
184→                                    >
185→                                        <OpinionsReplyCard opinionId={opinion.id} depth={depth + 1} />
186→                                    </motion.div>
187→                                )}
188→                            </AnimatePresence>
189→                        </div>
190→                    </motion.div>
191→                );
192→            })}
193→
194→            {hasNextPage && (
195→                <button className="rc-load-more" onClick={() => fetchNextPage()}>
196→                    {isFetchingNextPage ? 'Loading...' : 'Show more replies'}
197→                </button>
198→            )}
199→        </div>
200→    );
201→};
202→
203→export default OpinionsReplyCard;
