  1→import { useInfiniteQuery } from '@tanstack/react-query';
  2→import './sidebarOpinions.css'
  3→import { getOpinions } from '../../../API/Api';
  4→import { useNavigate } from 'react-router-dom';
  5→import { makeAuthedProfileClick, handleClickOpinion } from '../../../helpers/handleClicks';
  6→import { useAuth } from '../../Context/useAuth';
  7→import { BarLoader, MoonLoader } from 'react-spinners';
  8→import VerifiedBadge from '../Badge/VerifiedBadge';
  9→import formatPostDate from '../../../helpers/formatDateString';
 10→import MentionText from '../mentions/MentionText';
 11→import { getBadgeRingClass } from '../../utils/badgeRingClass';
 12→
 13→const SidebarOpinions = ({openEditor}) =>{
 14→    const {user, session, openAuthModal} = useAuth();
 15→
 16→    const handleOpenEditor = () =>{
 17→        if(!session) return openAuthModal();
 18→        openEditor();
 19→    }
 20→    const navigate = useNavigate();
 21→
 22→    const handleClickOpionionsProfile = makeAuthedProfileClick(navigate, session, openAuthModal);
 23→
 24→    const {data, isLoading, fetchNextPage, isFetchingNextPage, hasNextPage} = useInfiniteQuery({
 25→        queryKey: ['getOpinions'],
 26→        queryFn: ({pageParam = null}) => getOpinions(pageParam, 5),
 27→        getNextPageParam: (lastPage) =>{
 28→            if(lastPage?.hasMore){
 29→                const lastOpinion = lastPage?.data[lastPage?.data?.length - 1];
 30→                return lastOpinion.id;
 31→            } else {
 32→                return undefined
 33→            }
 34→        },
 35→    });
 36→
 37→    const handleClickSeeMore = () =>{
 38→        if(!isLoading && !isFetchingNextPage){
 39→            fetchNextPage();
 40→        }
 41→
 42→    }
 43→
 44→    const handleClickOpinionCard = handleClickOpinion(navigate);
 45→    const handleClickContent = (e, opinionId, userId) =>{
 46→        if(!session) return openAuthModal();
 47→        handleClickOpinionCard(e, opinionId, userId);
 48→    }
 49→
 50→    const opinions = data?.pages.flatMap((page) => page.data) || [];
 51→
 52→    if(opinions.length === 0){
 53→        return(
 54→            <div className='side-bar-opinions-parent-container'>
 55→                <div className='signal-container'>
 56→                    <p className='signal-header'>"Share what you believe. This is a free-speech space."</p>
 57→                    <button onClick={() => handleOpenEditor()} className='write-opinions-bttn'>
 58→                        Write opinions
 59→                    </button>
 60→                </div>
 61→                <div className='latest-opinions-container'>
 62→                    <div className='latest-opinions-header'>
 63→                        Latest opinions
 64→                    </div>
 65→                    <div className='sidebar-opinions-cards-container'>
 66→                        No opinions available
 67→                    </div>
 68→                </div>
 69→            </div>
 70→        )
 71→    }
 72→    if(isLoading){
 73→        return(
 74→            <div className='side-bar-opinions-parent-container'>
 75→                <div className='opinions-loading-container'>
 76→                    <MoonLoader size={25} color="var(--loader-color)" speedMultiplier={1} loading={isLoading}/>
 77→                </div>
 78→            </div>
 79→        )
 80→    }
 81→    return(
 82→        <>
 83→        <div className="side-bar-opinions-parent-container">
 84→            <div className='signal-container'>
 85→                <p className='signal-header'>"Share what you believe. This is a free-speech space."</p>
 86→                <button onClick={() => handleOpenEditor()} className='write-opinions-bttn'>
 87→                    Write opinions
 88→                </button>
 89→            </div>
 90→
 91→            <div className='latest-opinions-container'>
 92→                <div className='latest-opinions-header'>
 93→                    Latest opinions
 94→                </div>
 95→                <div className='sidebar-opinions-cards-container'>
 96→                    {opinions.map((opinionsData) => (
 97→                        <div key={opinionsData.id} className="so-card-wrapper">
 98→                            <div className="so-card">
 99→                                <div className="so-card-content">
100→                                    <div className="so-header-row">
101→                                        <div className={`so-avatar-outer ${getBadgeRingClass(opinionsData.users.badge)}`}>
102→                                            <img onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, opinionsData.user_id)} className="so-avatar" src={opinionsData.users.image_url || "../../assets/profile.jpg"} alt={`${opinionsData?.users?.name || "User"} profile picture`} />
103→                                        </div>
104→                                        <span onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, opinionsData.user_id)} className="so-username">{opinionsData.users.name}</span>
105→                                        <VerifiedBadge badge={opinionsData.users.badge} size={14} />
106→                                        <span className="so-dot">·</span>
107→                                        <span className="so-date">{formatPostDate(opinionsData.created_at)}</span>
108→                                    </div>
109→                                    <div className="so-body" onClick={(e) => handleClickContent(e, opinionsData.id, opinionsData.user_id)}>
110→                                        <MentionText text={opinionsData.opinion} />
111→                                    </div>
112→                                    <div className="so-action-row">
113→                                        <span className="so-reply-btn" onClick={(e) => handleClickContent(e, opinionsData.id, opinionsData.user_id)}>
114→                                            <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
115→                                                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
116→                                            </svg>
117→                                            Reply
118→                                        </span>
119→                                    </div>
120→                                </div>
121→                            </div>
122→                        </div>
123→                    ))}
124→                    {hasNextPage && (
125→                        <div onClick={() => handleClickSeeMore()} className='see-fullpage-bttn'>
126→                            See more
127→                        </div>
128→                    )}
129→
130→                </div>
131→            </div>
132→        </div>
133→        </>
134→    )
135→}
136→export default SidebarOpinions;
